TOOLS = [
    {
        "name": "web_search",
        "description": (
            "Search the web for current information. Use this for anything that "
            "may have changed since your training cutoff, including software versions, "
            "news, prices, regulations, and product documentation."
        ),
        "input_schema": {
            "type": "object",
            "properties": {
                "query": {
                    "type": "string",
                    "description": "A concise web search query.",
                },
                "num_results": {
                    "type": "integer",
                    "description": "Number of results to return (default 5, max 10).",
                    "default": 5,
                },
            },
            "required": ["query"],
        },
    }
]
